/* 低功耗分层架构 - 层级初始化 */
#include "stm32f4xx.h"
#include "power_manager.h"

/* 层级 1: 时钟门控 - 关闭未使用外设 */
static void clock_gate_init(void) {
    /* 关闭 GPIOE/F/G 时钟 - 节省约 3mA */
    RCC->AHB1ENR &= ~(RCC_AHB1ENR_GPIOEEN |
                       RCC_AHB1ENR_GPIOFEN |
                       RCC_AHB1ENR_GPIOGEN);
    /* 关闭 USB OTG、CRC 等不需用到的外设 */
    RCC->AHB1ENR &= ~RCC_AHB1ENR_CRCEN;
}

/* 层级 3: 电源域 - 降低运行电压 */
static void power_domain_optimize(void) {
    /* 切换至 Range 2 (1.8V)，支持更高频运行 */
    FLASH->ACR &= ~FLASH_ACR_PRFTEN;
    PWR->CR |= PWR_CR_VOS_0;
    while (!(PWR->CSR & PWR_CSR_VOSF)) {}
    FLASH->ACR |= FLASH_ACR_PRFTEN;
}

/* 层级 2: 休眠模式入口 */
void enter_stop_mode(void) {
    /* 配置所有非关键 GPIO 为模拟输入 - 降低漏电流 */
    for (uint8_t port = 0; port < 7; port++) {
        GPIO_Reg[port]->MODER = 0x00000000;
    }
    /* 配置唤醒引脚为外部中断 */
    SYSCFG->EXTICR[0] &= ~SYSCFG_EXTICR1_EXTI0_PA;
    SYSCFG->EXTICR[0] |= SYSCFG_EXTICR1_EXTI0_PC;
    EXTI->IMR |= EXTI_IMR_IM2;
    SCB->SCR |= SCB_SCR_SLEEPDEEP_Msk;
    __WFE();
    SystemClock_Config();
}

/* 完整 Stop 模式进入与恢复流程 */
/* STM32F405 | HSE 25MHz | SYSCLK 168MHz */

void lowpower_enter_stop(void) {
    /* 步骤 1: 关闭不需要的 HAL 外设时钟 */
    __HAL_RCC_DMA2_CLK_DISABLE();
    __HAL_RCC_USART2_CLK_DISABLE();

    /* 步骤 2: 配置唤醒引脚 - WKUP pin = PC2, 上升沿触发 */
    __HAL_RCC_GPIOC_CLK_ENABLE();
    GPIO_InitTypeDef GPIO_WKUP = {0};
    GPIO_WKUP.Pin = GPIO_PIN_2;
    GPIO_WKUP.Mode = GPIO_MODE_INPUT;
    GPIO_WKUP.Pull = GPIO_PULLUP;
    HAL_GPIO_Init(GPIOC, &GPIO_WKUP);

    /* 步骤 3: 清除旧的唤醒标志 */
    __HAL_PWR_CLEAR_FLAG(PWR_FLAG_WU);

    /* 步骤 4: 使能 WKUP pin */
    __HAL_PWR_WAKEUP_PIN_ENABLE(PWR_WAKEUP_PIN_2);

    /* 步骤 5: 将未用 GPIO 设为模拟输入 */
    GPIO_InitTypeDef GPIO_ANA = {0};
    GPIO_ANA.Mode = GPIO_MODE_ANALOG;
    GPIO_ANA.Pull = GPIO_NOPULL;
    for (uint32_t pin = 0; pin < 16; pin++) {
        GPIO_ANA.Pin = (1 << pin);
        HAL_GPIO_Init(GPIOA, &GPIO_ANA);
    }

    /* 步骤 6: 设置深度睡眠 - 必须, 否则 WFI 只进 Sleep */
    SCB->SCR |= SCB_SCR_SLEEPDEEP_Msk;

    /* 步骤 7: 进入 Stop - 用 WFE 等待唤醒事件 */
    __WFE();

    /* 唤醒后: 关闭 WKUP pin 节能 */
    __HAL_PWR_WAKEUP_PIN_DISABLE(PWR_WAKEUP_PIN_2);

    /* 步骤 8: 重新配置系统时钟 */
    SystemClock_Config();

    /* 步骤 9: 恢复外设时钟 */
    __HAL_RCC_DMA2_CLK_ENABLE();
    __HAL_RCC_USART2_CLK_ENABLE();
}

/* EXTI2 中断服务程序 - 唤醒后的第一个 ISR */
void EXTI2_IRQHandler(void) {
    HAL_GPIO_EXTI_IRQHandler(GPIO_PIN_2);
}

/* 低功耗预算计算器 */
/* 帮助在设计阶段量化各部分的功耗贡献 */

typedef struct {
    const char* name;
    float current_uA;
    float active_seconds;
    float duty_cycle;
    float avg_current_uA;
} power_block_t;

power_block_t nodes[] = {
    {"MCU_Stop",      20.0f,   0.0f/86400.0f,  0.0f},
    {"MCU_Running",  12000.0f,  1.0f/86400.0f,  1.0f/86400.0f},
    {"TempSensor",      2.0f,  1.0f/86400.0f,  1.0f/86400.0f},
    {"LDO_Iq",          2.0f,  1.0f,           1.0f},
};

float calculate_total_uA(power_block_t *blocks, int count) {
    float total = 0.0f;
    for (int i = 0; i < count; i++) {
        blocks[i].avg_current_uA = blocks[i].current_uA * blocks[i].duty_cycle;
        total += blocks[i].avg_current_uA;
        printf("%-16s  %.2f uA x %.8f = %.3f uA (avg)\n",
               blocks[i].name, blocks[i].current_uA,
               blocks[i].duty_cycle, blocks[i].avg_current_uA);
    }
    return total;
}

/* 改进前：全局变量 + 散乱逻辑 */
/* 问题: 全局状态、无返回值检查、GPIO 配置散落在各处 */
int g_power_mode = 0;

void go_to_sleep_bad(void) {
    RCC->AHB1ENR &= ~(RCC_AHB1ENR_GPIOEEN | RCC_AHB1ENR_GPIOFEN);
    RCC->AHB2ENR &= ~RCC_AHB2ENR_OTGFSEN;
    GPIOA->MODER &= ~(0x3 << 0);
    GPIOB->MODER &= ~(0x3 << 2);
    SCB->SCR |= SCB_SCR_SLEEPDEEP_Msk;
    g_power_mode = 1;
    __WFE();
    HAL_GPIO_TogglePin(GPIOB, GPIO_PIN_5);
}

/* 改进后：层次化电源管理 */
typedef enum { PWR_OK = 0, PWR_FAIL, PWR_UNSUPPORTED } PowerStatus;
typedef enum { PWR_MODE_RUN, PWR_MODE_STOP, PWR_MODE_STANDBY } PowerMode;

typedef struct {
    uint32_t ahb_mask;
    uint32_t apb1_mask;
    uint32_t apb2_mask;
    uint32_t wake_pin;
    PowerMode  target_mode;
} power_config_t;

typedef struct {
    PowerStatus (*init)(void);
    PowerStatus (*control)(power_config_t*);
} power_module_t;

static PowerStatus clock_gate_init(void) {
    RCC->AHB1ENR &= ~(RCC_AHB1ENR_GPIOEEN | RCC_AHB1ENR_GPIOFEN | RCC_AHB1ENR_GPIOGEN);
    RCC->AHB2ENR &= ~RCC_AHB2ENR_OTGFSEN;
    return PWR_OK;
}

static PowerStatus sleep_enter(power_config_t* cfg) {
    __HAL_PWR_CLEAR_FLAG(PWR_FLAG_WU);
    __HAL_PWR_WAKEUP_PIN_ENABLE(cfg->wake_pin);
    SCB->SCR |= SCB_SCR_SLEEPDEEP_Msk;
    if (cfg->target_mode == PWR_MODE_STOP) {
        __WFE();
    } else if (cfg->target_mode == PWR_MODE_STANDBY) {
        PWR->CR |= PWR_CR_CSBF;
        PWR->CR |= PWR_CR_PDDS;
        __WFI();
    }
    return PWR_OK;
}
